;(function(jsPDFAPI) {
  var font =
    ''
  var callAddFont = function() {
    this.addFileToVFS('NotoNaskhArabic-Regular.ttf', font)
    this.addFont("NotoNaskhArabic-Regular.ttf", "NotoNaskhArabic", "normal")
    console.log('font added')

  }
  jsPDFAPI.events.push(['addFonts', callAddFont])
})(jsPDF.API)
